from .. import ICoveragePyEbyeAggregatorfrom ..._private.e_cov_reporttype import ECoverageReportTypefrom .._private.json_covebyeaggr import JsonCoverageEbyeAggregatorclass CoveragePyEbyeAggregatorFactory:	"""		Rappresenta una factory per ogni `ICoveragePyEbyeAggregator`	"""			@classmethod	def create(			cls,			report_type: ECoverageReportType,	) -> ICoveragePyEbyeAggregator:		"""			Istanzia un nuovo aggregatore entity-by-entity di dati di coverage, provenienti da coverage.py,			che supporta la tipologia di report specificata						Parameters			----------				report_type: ECoverageReportType					Un valore `ECoverageReportType` rappresentante la tipologia di report di coverage.py					supportato per l' oggetto `ICoveragePyEbyeAggregator` richiesto								Returns			-------				ICoveragePyEbyeAggregator					Un oggetto `ICoveragePyEbyeAggregator` che rappresenta l' aggregatore entity-by-entity dei dati					di coverage, provenienti da coverage.py, che supporta la tipologia di report richiesto								Raises			------				NotImplementedError					Si verifica se si fornisce un `report_type` per cui non è implementato nessun					`ICoveragePyEbyeAggregator`		"""		obj: ICoveragePyEbyeAggregator				match report_type:			case ECoverageReportType.JSON:				obj = JsonCoverageEbyeAggregator()					return obj